/*! Leaflet 1.9.4 - Local Copy - Simplified for Navigation */
(function(global, factory) {
  global.L = factory();
}(typeof window !== 'undefined' ? window : this, function() {
  'use strict';

  const L = {
    version: '1.9.4',
    
    // Create a map
    map: function(container, options) {
      return new Map(container, options);
    },
    
    // Tile layer
    tileLayer: function(url, options) {
      return new TileLayer(url, options);
    },
    
    // Marker
    marker: function(latlng, options) {
      return new Marker(latlng, options);
    },
    
    // Polyline
    polyline: function(latlngs, options) {
      return new Polyline(latlngs, options);
    },
    
    // Circle
    circle: function(latlng, options) {
      return new Circle(latlng, options);
    },
    
    // Popup
    popup: function(options) {
      return new Popup(options);
    },
    
    // Utility functions
    latLng: function(lat, lng) {
      return { lat, lng };
    },
    
    latLngBounds: function(corner1, corner2) {
      return new LatLngBounds(corner1, corner2);
    },
    
    DomUtil: {
      get: function(id) {
        return typeof id === 'string' ? document.getElementById(id) : id;
      },
      create: function(tag, className, container) {
        const el = document.createElement(tag);
        if (className) el.className = className;
        if (container) container.appendChild(el);
        return el;
      },
      remove: function(el) {
        if (el.parentNode) el.parentNode.removeChild(el);
      },
      addClass: function(el, name) {
        if (!el.classList.contains(name)) el.classList.add(name);
      },
      removeClass: function(el, name) {
        el.classList.remove(name);
      },
      setClass: function(el, name) {
        el.className = name;
      },
      getClass: function(el) {
        return el.className;
      }
    },
    
    Util: {
      extend: function(dest, src) {
        for (let key in src) {
          if (src.hasOwnProperty(key)) {
            dest[key] = src[key];
          }
        }
        return dest;
      }
    }
  };

  // Map class
  function Map(container, options = {}) {
    this.container = L.DomUtil.get(container);
    this.options = L.Util.extend({
      center: [20.5937, 78.9629],
      zoom: 5,
      layers: [],
      maxZoom: 19
    }, options);
    
    this.layers = [];
    this.markers = [];
    this._handlers = {};
    
    this._init();
  }

  Map.prototype = {
    _init: function() {
      // Setup container
      this.container.style.position = 'relative';
      this.container.style.overflow = 'hidden';
      L.DomUtil.setClass(this.container, 'leaflet-container');
      
      // Create canvas/div for rendering
      this._mapPane = L.DomUtil.create('div', 'leaflet-map-pane', this.container);
      this._tilePane = L.DomUtil.create('div', 'leaflet-tile-pane', this._mapPane);
      this._objectsPane = L.DomUtil.create('div', 'leaflet-objects-pane', this._mapPane);
      
      // Setup events
      this._setupEvents();
      
      // Render initial view
      this._updateSize();
    },
    
    _setupEvents: function() {
      this.container.addEventListener('click', (e) => this._onMapClick(e));
      this.container.addEventListener('mousemove', (e) => this._onMouseMove(e));
      window.addEventListener('resize', () => this.invalidateSize());
    },
    
    _onMapClick: function(e) {
      if (this._handlers['click']) {
        const latlng = this._getLatLngFromEvent(e);
        this._handlers['click']({ latlng });
      }
    },
    
    _onMouseMove: function(e) {
      if (this._handlers['mousemove']) {
        const latlng = this._getLatLngFromEvent(e);
        this._handlers['mousemove']({ latlng });
      }
    },
    
    _getLatLngFromEvent: function(e) {
      const rect = this.container.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      
      const width = this.container.clientWidth;
      const height = this.container.clientHeight;
      
      const center = this.options.center;
      const zoom = this.options.zoom;
      
      // Simple mercator projection
      const scale = Math.pow(2, zoom);
      const x0 = (center[1] + 180) / 360 * 256 * scale;
      const y0 = (1 - Math.log(Math.tan((center[0] + 90) * Math.PI / 360)) / Math.PI) / 2 * 256 * scale;
      
      const xp = x0 - width / 2;
      const yp = y0 - height / 2;
      
      const x1 = xp + x;
      const y1 = yp + y;
      
      const lng = (x1 / (256 * scale)) * 360 - 180;
      const lat = (Math.atan(Math.sinh(Math.PI * (1 - 2 * y1 / (256 * scale)))) * 180 / Math.PI);
      
      return { lat, lng };
    },
    
    _updateSize: function() {
      this._mapPane.style.width = this.container.clientWidth + 'px';
      this._mapPane.style.height = this.container.clientHeight + 'px';
    },
    
    setView: function(center, zoom) {
      this.options.center = center;
      this.options.zoom = zoom;
      this._updateView();
      return this;
    },
    
    _updateView: function() {
      this.layers.forEach(layer => {
        if (layer._update) layer._update();
      });
    },
    
    on: function(type, handler) {
      this._handlers[type] = handler;
      return this;
    },
    
    addLayer: function(layer) {
      this.layers.push(layer);
      layer.addTo(this);
      return this;
    },
    
    removeLayer: function(layer) {
      const idx = this.layers.indexOf(layer);
      if (idx > -1) this.layers.splice(idx, 1);
      if (layer._container && layer._container.parentNode) {
        layer._container.parentNode.removeChild(layer._container);
      }
      return this;
    },
    
    fitBounds: function(bounds) {
      const minLat = Math.min(bounds[0][0], bounds[1][0]);
      const maxLat = Math.max(bounds[0][0], bounds[1][0]);
      const minLng = Math.min(bounds[0][1], bounds[1][1]);
      const maxLng = Math.max(bounds[0][1], bounds[1][1]);
      
      const centerLat = (minLat + maxLat) / 2;
      const centerLng = (minLng + maxLng) / 2;
      
      // Simple zoom calculation
      const latDiff = maxLat - minLat;
      const lngDiff = maxLng - minLng;
      const maxDiff = Math.max(latDiff, lngDiff);
      const zoom = Math.max(1, Math.floor(10 - Math.log2(maxDiff)));
      
      this.setView([centerLat, centerLng], zoom);
      return this;
    },
    
    invalidateSize: function() {
      this._updateSize();
      this._updateView();
      return this;
    },
    
    getContainer: function() {
      return this.container;
    }
  };

  // TileLayer class
  function TileLayer(url, options = {}) {
    this.url = url;
    this.options = L.Util.extend({
      maxZoom: 19,
      attribution: ''
    }, options);
    this._tiles = {};
  }

  TileLayer.prototype = {
    addTo: function(map) {
      this.map = map;
      this._update();
      return this;
    },
    
    _update: function() {
      if (!this.map || !this._container) return;
      
      const zoom = this.map.options.zoom;
      const center = this.map.options.center;
      const container = this.map._tilePane;
      
      // Clear old tiles
      while (container.firstChild) {
        container.removeChild(container.firstChild);
      }
      
      // Simple tile loading
      const scale = Math.pow(2, zoom);
      const tileSize = 256;
      
      const centerX = ((center[1] + 180) / 360) * scale;
      const centerY = ((90 - center[0]) / 180) * scale;
      
      const minTileX = Math.max(0, Math.floor(centerX - 2));
      const maxTileX = Math.min(scale - 1, Math.ceil(centerX + 2));
      const minTileY = Math.max(0, Math.floor(centerY - 2));
      const maxTileY = Math.min(scale - 1, Math.ceil(centerY + 2));
      
      for (let x = minTileX; x <= maxTileX; x++) {
        for (let y = minTileY; y <= maxTileY; y++) {
          const tileUrl = this.url
            .replace('{z}', zoom)
            .replace('{x}', x)
            .replace('{y}', y)
            .replace('{s}', ['a', 'b', 'c'][Math.random() * 3 | 0]);
          
          const img = document.createElement('img');
          img.src = tileUrl;
          img.style.position = 'absolute';
          img.style.left = ((x - centerX) * tileSize) + (this.map.container.clientWidth / 2) + 'px';
          img.style.top = ((y - centerY) * tileSize) + (this.map.container.clientHeight / 2) + 'px';
          img.style.width = tileSize + 'px';
          img.style.height = tileSize + 'px';
          img.style.opacity = '0.8';
          
          container.appendChild(img);
        }
      }
    }
  };

  // Marker class
  function Marker(latlng, options = {}) {
    this.latlng = latlng;
    this.options = L.Util.extend({
      icon: null,
      draggable: false
    }, options);
  }

  Marker.prototype = {
    addTo: function(map) {
      this.map = map;
      this._render();
      return this;
    },
    
    _render: function() {
      if (!this.map) return;
      
      const container = this.map._objectsPane;
      this._container = L.DomUtil.create('div', 'leaflet-marker', container);
      
      const pos = this._getPixelPos();
      this._container.style.left = pos.x + 'px';
      this._container.style.top = pos.y + 'px';
      this._container.style.zIndex = 999;
      
      if (this.options.icon) {
        this._container.style.backgroundImage = this.options.icon.url;
        this._container.style.backgroundSize = '100% 100%';
        this._container.style.width = this.options.icon.size[0] + 'px';
        this._container.style.height = this.options.icon.size[1] + 'px';
      }
    },
    
    _getPixelPos: function() {
      const map = this.map;
      const center = map.options.center;
      const zoom = map.options.zoom;
      
      const scale = Math.pow(2, zoom);
      const x0 = ((center[1] + 180) / 360) * 256 * scale;
      const y0 = ((90 - center[0]) / 180) * 256 * scale;
      
      const x1 = ((this.latlng.lng + 180) / 360) * 256 * scale;
      const y1 = ((90 - this.latlng.lat) / 180) * 256 * scale;
      
      const x = (x1 - x0) + (map.container.clientWidth / 2);
      const y = (y1 - y0) + (map.container.clientHeight / 2);
      
      return { x, y };
    },
    
    setLatLng: function(latlng) {
      this.latlng = latlng;
      if (this._container) {
        const pos = this._getPixelPos();
        this._container.style.left = pos.x + 'px';
        this._container.style.top = pos.y + 'px';
      }
      return this;
    },
    
    getLatLng: function() {
      return this.latlng;
    }
  };

  // Circle class
  function Circle(latlng, options = {}) {
    this.latlng = latlng;
    this.options = L.Util.extend({
      radius: 500,
      color: '#3388ff',
      weight: 2,
      opacity: 0.8,
      fillColor: '#3388ff',
      fillOpacity: 0.2
    }, options);
  }

  Circle.prototype = {
    addTo: function(map) {
      this.map = map;
      this._render();
      return this;
    },
    
    _render: function() {
      if (!this.map) return;
      
      const container = this.map._objectsPane;
      this._container = L.DomUtil.create('div', 'leaflet-circle', container);
      
      const pos = this._getPixelPos();
      const radius = this._getPixelRadius();
      
      this._container.style.position = 'absolute';
      this._container.style.left = (pos.x - radius) + 'px';
      this._container.style.top = (pos.y - radius) + 'px';
      this._container.style.width = (radius * 2) + 'px';
      this._container.style.height = (radius * 2) + 'px';
      this._container.style.borderRadius = '50%';
      this._container.style.border = this.options.weight + 'px solid ' + this.options.color;
      this._container.style.backgroundColor = this.options.fillColor;
      this._container.style.opacity = this.options.fillOpacity;
      this._container.style.zIndex = 100;
    },
    
    _getPixelPos: function() {
      const map = this.map;
      const center = map.options.center;
      const zoom = map.options.zoom;
      
      const scale = Math.pow(2, zoom);
      const x0 = ((center[1] + 180) / 360) * 256 * scale;
      const y0 = ((90 - center[0]) / 180) * 256 * scale;
      
      const x1 = ((this.latlng.lng + 180) / 360) * 256 * scale;
      const y1 = ((90 - this.latlng.lat) / 180) * 256 * scale;
      
      const x = (x1 - x0) + (map.container.clientWidth / 2);
      const y = (y1 - y0) + (map.container.clientHeight / 2);
      
      return { x, y };
    },
    
    _getPixelRadius: function() {
      // Simplified pixel radius calculation
      return Math.max(5, this.options.radius / 100000);
    }
  };

  // Polyline class
  function Polyline(latlngs, options = {}) {
    this.latlngs = latlngs;
    this.options = L.Util.extend({
      color: '#3388ff',
      weight: 2,
      opacity: 0.7,
      lineCap: 'round',
      lineJoin: 'round',
      dashArray: null,
      fillColor: null,
      fillOpacity: 0.2
    }, options);
  }

  Polyline.prototype = {
    addTo: function(map) {
      this.map = map;
      this._render();
      return this;
    },
    
    _render: function() {
      if (!this.map) return;
      
      const container = this.map._objectsPane;
      const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      svg.style.position = 'absolute';
      svg.style.top = '0';
      svg.style.left = '0';
      svg.style.width = this.map.container.clientWidth + 'px';
      svg.style.height = this.map.container.clientHeight + 'px';
      svg.style.pointerEvents = 'none';
      svg.style.zIndex = 200;
      
      const polyline = document.createElementNS('http://www.w3.org/2000/svg', 'polyline');
      polyline.setAttribute('fill', 'none');
      polyline.setAttribute('stroke', this.options.color);
      polyline.setAttribute('stroke-width', this.options.weight);
      polyline.setAttribute('stroke-opacity', this.options.opacity);
      polyline.setAttribute('stroke-linecap', this.options.lineCap);
      polyline.setAttribute('stroke-linejoin', this.options.lineJoin);
      
      const points = this.latlngs.map(latlng => {
        const pos = this._getPixelPos(latlng);
        return pos.x + ',' + pos.y;
      }).join(' ');
      
      polyline.setAttribute('points', points);
      svg.appendChild(polyline);
      container.appendChild(svg);
      this._container = svg;
    },
    
    _getPixelPos: function(latlng) {
      const map = this.map;
      const center = map.options.center;
      const zoom = map.options.zoom;
      
      const scale = Math.pow(2, zoom);
      const x0 = ((center[1] + 180) / 360) * 256 * scale;
      const y0 = ((90 - center[0]) / 180) * 256 * scale;
      
      const x1 = ((latlng.lng + 180) / 360) * 256 * scale;
      const y1 = ((90 - latlng.lat) / 180) * 256 * scale;
      
      const x = (x1 - x0) + (map.container.clientWidth / 2);
      const y = (y1 - y0) + (map.container.clientHeight / 2);
      
      return { x, y };
    }
  };

  // Popup class
  function Popup(options = {}) {
    this.options = L.Util.extend({
      minWidth: 50,
      maxWidth: 300,
      maxHeight: null,
      autoClose: true,
      closeButton: true,
      closeOnClick: null,
      className: ''
    }, options);
  }

  Popup.prototype = {
    setLatLng: function(latlng) {
      this._latlng = latlng;
      return this;
    },
    
    setContent: function(content) {
      this._content = content;
      return this;
    }
  };

  // LatLngBounds class
  function LatLngBounds(corner1, corner2) {
    this._southWest = corner1;
    this._northEast = corner2;
  }

  LatLngBounds.prototype = {
    getSouthWest: function() {
      return this._southWest;
    },
    
    getNorthEast: function() {
      return this._northEast;
    }
  };

  // Export
  L.Map = Map;
  L.TileLayer = TileLayer;
  L.Marker = Marker;
  L.Circle = Circle;
  L.Polyline = Polyline;
  L.Popup = Popup;
  L.LatLngBounds = LatLngBounds;

  return L;
}));